import React from 'react';
import { useNavigate } from 'react-router-dom';

const formatPrice = (price) => {
  if (!price && price !== 0) return 'N/A';
  return `$${Number(price).toLocaleString('en-AU')}/wk`;
};

const RentalCard = ({ rental }) => {
  const navigate = useNavigate();

  return (
    <article
      className="rental-card"
      onClick={() => navigate(`/rental/${rental.id}`)}
      role="button"
      tabIndex={0}
      onKeyDown={(e) => e.key === 'Enter' && navigate(`/rental/${rental.id}`)}
      aria-label={`View details for ${rental.address || 'rental property'}`}
    >
      <div className="rental-card__header">
        <span className="rental-card__type">{rental.property_type || 'Property'}</span>
        <span className="rental-card__price">{formatPrice(rental.price)}</span>
      </div>
      <h3 className="rental-card__address">{rental.address || 'Address not available'}</h3>
      <div className="rental-card__meta">
        <span>{rental.suburb}, {rental.state}</span>
        <span className="rental-card__postcode">{rental.postcode}</span>
      </div>
      <div className="rental-card__details">
        {rental.bedrooms != null && (
          <span className="rental-card__detail">
            <span>🛏</span> {rental.bedrooms} bed
          </span>
        )}
        {rental.bathrooms != null && (
          <span className="rental-card__detail">
            <span>🚿</span> {rental.bathrooms} bath
          </span>
        )}
        {rental.parking_spaces != null && (
          <span className="rental-card__detail">
            <span>🚗</span> {rental.parking_spaces} park
          </span>
        )}
      </div>
    </article>
  );
};

export default RentalCard;
